from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English paragraph.  This version first aggregates information by
    mission, allowing us to produce a single complex sentence that mentions the
    commander, backup pilot, crew members and operator of a mission.  Remaining
    astronaut‑specific facts are rendered in short sentences.
    """
    if not triples:
        return ""

    # ---------- Helpers ----------
    def fmt_date(d: str) -> str:
        try:
            from datetime import datetime
            dt = datetime.strptime(d, "%Y-%m-%d")
            return dt.strftime("%B %-d, %Y")
        except Exception:
            return d

    def simple_phrase(pred: str, obj: str) -> str:
        """Phrase for astronaut‑centric predicates (birthDate, nationality, …)."""
        obj = obj.strip().strip('"')
        p = pred.lower().replace(" ", "")
        if p == "birthdate":
            return f"was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"was born in {obj}"
        if p == "deathdate":
            return f"died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"died in {obj}"
        if p == "nationality":
            low = obj.lower()
            if low in ("united states", "usa", "united states of america"):
                return "is an American astronaut"
            return f"is from {obj}"
        if p == "occupation":
            return f"served as a {obj}"
        if p == "status":
            low = obj.lower()
            if low == "retired":
                return "is retired"
            return f"is {low}"
        if p == "selectedbynasa":
            return f"was selected by NASA in {obj}"
        if p == "almaMater":
            return f"graduated from {obj}"
        if p == "timeinspace":
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                if hrs:
                    return f"spent {hrs} hour{'s' if hrs>1 else ''}" + (f" and {rem} minute{'s' if rem!=1 else ''}" if rem else "") + " in space"
                else:
                    return f"spent {rem} minute{'s' if rem!=1 else ''} in space"
            except Exception:
                return f"spent {obj} minutes in space"
        if p == "award":
            return f"received the {obj}"
        if p == "awards":
            return f"received {obj} awards"
        if p == "ribbonaward":
            return f"was awarded the {obj}"
        if p == "alternativename":
            return f"is also known as {obj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"served as Chief of the Astronaut Office in {obj}"
        if p == "representative":
            return f"was the representative of {obj}"
        if p == "bird":
            return f"The {obj.lower()} is a bird found in {obj}"
        # fallback
        return obj

    # ---------- Aggregate by mission ----------
    from collections import defaultdict

    mission_info = defaultdict(lambda: {
        "commander": None,
        "backupPilot": None,
        "crew": [],
        "operator": None,
    })
    astronaut_facts = defaultdict(list)   # subject -> list of phrases

    for t in triples:
        subj, pred, obj = t.subject, t.predicate, t.object
        p = pred.lower().replace(" ", "")
        # Mission‑centric predicates
        if p == "commander" and subj in mission_info:
            mission_info[subj]["commander"] = obj.strip().strip('"')
        elif p == "backuppilot" and subj in mission_info:
            mission_info[subj]["backupPilot"] = obj.strip().strip('"')
        elif p == "operator" and subj in mission_info:
            mission_info[subj]["operator"] = obj.strip().strip('"')
        elif p == "mission":
            # subj is an astronaut, obj is a mission name
            mission = obj.strip().strip('"')
            mission_info[mission]["crew"].append(subj.strip())
        else:
            # treat as astronaut‑centric fact
            astronaut_facts[subj].append(simple_phrase(pred, obj))

    # Build mission‑centric sentences
    mission_sentences = []
    for mission, info in mission_info.items():
        parts = []
        if info["commander"]:
            parts.append(f"{info['commander']} was the commander of {mission}")
        if info["backupPilot"]:
            parts.append(f"{info['backupPilot']} was the backup pilot of {mission}")
        if info["crew"]:
            crew_list = ", ".join(info["crew"])
            parts.append(f"The crew of {mission} included {crew_list}")
        if info["operator"]:
            parts.append(f"The mission was operated by {info['operator']}")
        if parts:
            mission_sentences.append(", ".join(parts) + ".")

    # Build astronaut‑centric sentences
    astronaut_sentences = []
    for subj, phrases in astronaut_facts.items():
        if phrases:
            astronaut_sentences.append(f"{subj} " + ", ".join(phrases) + ".")

    # Combine everything
    return " ".join(mission_sentences + astronaut_sentences)

# EVOLVE-BLOCK-END

